diff --git a/llvm/lib/Transforms/InstCombine/InstCombineCompares.cpp b/llvm/lib/Transforms/InstCombine/InstCombineCompares.cpp
index fdadf729fbd5..956e03277932 100644
--- a/llvm/lib/Transforms/InstCombine/InstCombineCompares.cpp
+++ b/llvm/lib/Transforms/InstCombine/InstCombineCompares.cpp
@@ -7885,6 +7885,7 @@ static Instruction *foldFCmpFNegCommonOp(FCmpInst &I) {
   return new FCmpInst(Pred, Op0, Zero, "", &I);
 }

+
 Instruction *InstCombinerImpl::visitFCmpInst(FCmpInst &I) {
   bool Changed = false;

@@ -7907,20 +7908,21 @@ Instruction *InstCombinerImpl::visitFCmpInst(FCmpInst &I) {
   assert(OpType == Op1->getType() && "fcmp with different-typed operands?");
   if (Op0 == Op1) {
     switch (Pred) {
-      default: break;
-    case FCmpInst::FCMP_UNO:    // True if unordered: isnan(X) | isnan(Y)
-    case FCmpInst::FCMP_ULT:    // True if unordered or less than
-    case FCmpInst::FCMP_UGT:    // True if unordered or greater than
-    case FCmpInst::FCMP_UNE:    // True if unordered or not equal
+    default:
+      break;
+    case FCmpInst::FCMP_UNO: // True if unordered: isnan(X) | isnan(Y)
+    case FCmpInst::FCMP_ULT: // True if unordered or less than
+    case FCmpInst::FCMP_UGT: // True if unordered or greater than
+    case FCmpInst::FCMP_UNE: // True if unordered or not equal
       // Canonicalize these to be 'fcmp uno %X, 0.0'.
       I.setPredicate(FCmpInst::FCMP_UNO);
       I.setOperand(1, Constant::getNullValue(OpType));
       return &I;

-    case FCmpInst::FCMP_ORD:    // True if ordered (no nans)
-    case FCmpInst::FCMP_OEQ:    // True if ordered and equal
-    case FCmpInst::FCMP_OGE:    // True if ordered and greater than or equal
-    case FCmpInst::FCMP_OLE:    // True if ordered and less than or equal
+    case FCmpInst::FCMP_ORD: // True if ordered (no nans)
+    case FCmpInst::FCMP_OEQ: // True if ordered and equal
+    case FCmpInst::FCMP_OGE: // True if ordered and greater than or equal
+    case FCmpInst::FCMP_OLE: // True if ordered and less than or equal
       // Canonicalize these to be 'fcmp ord %X, 0.0'.
       I.setPredicate(FCmpInst::FCMP_ORD);
       I.setOperand(1, Constant::getNullValue(OpType));
@@ -7976,6 +7978,75 @@ Instruction *InstCombinerImpl::visitFCmpInst(FCmpInst &I) {
   if (match(Op1, m_AnyZeroFP()) && !match(Op1, m_PosZeroFP()))
     return replaceOperand(I, 1, ConstantFP::getZero(OpType));

+  // Fold compare-to-zero of a select-based abs idiom:
+  //   %c = fcmp oge/ogt/ole/olt X, 0.0
+  //   %n = fneg X
+  //   %s = select %c, X, %n          ; or select %c, %n, X
+  //   fcmp oeq/ueq %s, 0.0  -->  fcmp oeq/ueq X, 0.0
+  //
+  // This is valid because the select computes either X or -X based on the sign
+  // test, and that result is zero iff X is zero. NaNs are preserved because
+  // fneg(NaN) is NaN and ordered predicates in the select condition send NaNs
+  // down the non-selected ordered path without changing the compare-to-zero
+  // result.
+  if ((Pred == FCmpInst::FCMP_OEQ || Pred == FCmpInst::FCMP_UEQ) &&
+      match(Op1, m_PosZeroFP())) {
+    Value *Cond, *TrueVal, *FalseVal;
+    if (match(Op0, m_Select(m_Value(Cond), m_Value(TrueVal), m_Value(FalseVal)))) {
+      Value *CmpX;
+      const APFloat *CmpC;
+      FCmpInst::Predicate SelPred;
+
+      if (match(Cond, m_FCmp(SelPred, m_Value(CmpX), m_APFloat(CmpC))) &&
+          CmpC->isZero() &&
+          !CmpC->isNegative()) {
+        Value *NegX;
+
+        auto IsAbsSelect = [&](FCmpInst::Predicate P, Value *T, Value *F) {
+          return (P == FCmpInst::FCMP_OGE || P == FCmpInst::FCMP_OGT) &&
+                 T == CmpX && match(F, m_FNeg(m_Specific(CmpX)));
+        };
+        auto IsNegAbsSelect = [&](FCmpInst::Predicate P, Value *T, Value *F) {
+          return (P == FCmpInst::FCMP_OLE || P == FCmpInst::FCMP_OLT) &&
+                 T == CmpX && match(F, m_FNeg(m_Specific(CmpX)));
+        };
+
+        if (IsAbsSelect(SelPred, TrueVal, FalseVal) ||
+            IsAbsSelect(FCmpInst::getSwappedPredicate(SelPred), FalseVal,
+                        TrueVal) ||
+            IsNegAbsSelect(SelPred, FalseVal, TrueVal) ||
+            IsNegAbsSelect(FCmpInst::getSwappedPredicate(SelPred), TrueVal,
+                           FalseVal)) {
+          return new FCmpInst(Pred, CmpX, ConstantFP::getZero(OpType), "", &I);
+        }
+
+        if (match(TrueVal, m_FNeg(m_Specific(CmpX))) && FalseVal == CmpX) {
+          switch (SelPred) {
+          case FCmpInst::FCMP_OLT:
+          case FCmpInst::FCMP_OLE:
+          case FCmpInst::FCMP_OGT:
+          case FCmpInst::FCMP_OGE:
+            return new FCmpInst(Pred, CmpX, ConstantFP::getZero(OpType), "", &I);
+          default:
+            break;
+          }
+        }
+
+        if (TrueVal == CmpX && match(FalseVal, m_FNeg(m_Specific(CmpX)))) {
+          switch (SelPred) {
+          case FCmpInst::FCMP_OLT:
+          case FCmpInst::FCMP_OLE:
+          case FCmpInst::FCMP_OGT:
+          case FCmpInst::FCMP_OGE:
+            return new FCmpInst(Pred, CmpX, ConstantFP::getZero(OpType), "", &I);
+          default:
+            break;
+          }
+        }
+      }
+    }
+  }
+
   // Canonicalize:
   // fcmp olt X, +inf -> fcmp one X, +inf
   // fcmp ole X, +inf -> fcmp ord X, 0
@@ -8065,7 +8136,7 @@ Instruction *InstCombinerImpl::visitFCmpInst(FCmpInst &I) {
                   cast<LoadInst>(LHSI), GEP, GV, I))
             return Res;
       break;
-  }
+    }
   }

   if (Instruction *R = foldFabsWithFcmpZero(I, *this))
@@ -8180,3 +8251,4 @@ Instruction *InstCombinerImpl::visitFCmpInst(FCmpInst &I) {

   return Changed ? &I : nullptr;
 }
+

